import React, { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { Download, Trash2, Upload } from 'lucide-react';
import { reportsApi } from '../api/reports';
import { exportApi } from '../api/export';
import DataTable from '../components/DataTable';
import MonthFilter from '../components/MonthFilter';
import FileImport from '../components/FileImport';
import Card from '../components/Card';

const Labs: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'data' | 'strategy'>('data');
  const [selectedMonth, setSelectedMonth] = useState('');

  const { data: reports = [], isLoading: reportsLoading } = useQuery({
    queryKey: ['reports', selectedMonth],
    queryFn: () => reportsApi.getReports(selectedMonth ? { month: selectedMonth } : undefined),
  });

  const { data: rollups = [], isLoading: rollupsLoading } = useQuery({
    queryKey: ['rollups'],
    queryFn: () => reportsApi.getRollups(),
    enabled: activeTab === 'strategy',
  });

  // Extract unique months from reports
  const availableMonths = React.useMemo(() => {
    const months = new Set<string>();
    reports.forEach(report => {
      const date = new Date(report.report_date);
      const monthKey = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
      months.add(monthKey);
    });
    return Array.from(months).sort().reverse();
  }, [reports]);

  const handleClearAll = () => {
    const confirmed = window.confirm(
      'Are you sure you want to clear all data? This action cannot be undone.'
    );
    if (confirmed) {
      // Handle clear all - would need mutation here
      console.log('Clear all data');
    }
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <h1 className="text-2xl font-bold text-gray-900 mb-8">Action Labs</h1>

      {/* Tab Navigation */}
      <div className="border-b border-gray-200 mb-8">
        <nav className="-mb-px flex space-x-8">
          <button
            onClick={() => setActiveTab('data')}
            className={`py-2 px-1 border-b-2 font-medium text-sm ${
              activeTab === 'data'
                ? 'border-primary-500 text-primary-600'
                : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
            }`}
          >
            Data Entry
          </button>
          <button
            onClick={() => setActiveTab('strategy')}
            className={`py-2 px-1 border-b-2 font-medium text-sm ${
              activeTab === 'strategy'
                ? 'border-primary-500 text-primary-600'
                : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
            }`}
          >
            Strategy View
          </button>
        </nav>
      </div>

      {/* Data Entry Tab */}
      {activeTab === 'data' && (
        <div className="space-y-6">
          {/* Header Actions */}
          <Card>
            <div className="flex flex-wrap items-center justify-between gap-4">
              <h2 className="text-lg font-semibold text-gray-900">Data Management</h2>
              
              <div className="flex flex-wrap items-center gap-4">
                <FileImport />
                
                <a
                  href={exportApi.exportCsv()}
                  className="btn-secondary inline-flex items-center"
                >
                  <Download className="w-4 h-4 mr-2" />
                  Export CSV
                </a>
                
                <button
                  onClick={handleClearAll}
                  className="btn-danger inline-flex items-center"
                >
                  <Trash2 className="w-4 h-4 mr-2" />
                  Clear All Data
                </button>
              </div>
            </div>
          </Card>

          {/* Controls */}
          <Card>
            <div className="flex items-center justify-between">
              <MonthFilter
                value={selectedMonth}
                onChange={setSelectedMonth}
                months={availableMonths}
                loading={reportsLoading}
              />
              
              <div className="text-sm text-gray-600">
                {reports.length} record{reports.length !== 1 ? 's' : ''} found
              </div>
            </div>
          </Card>

          {/* Data Table */}
          <DataTable
            data={reports}
            loading={reportsLoading}
            onView={(report) => {
              alert(JSON.stringify(report, null, 2));
            }}
            onEdit={(report) => {
              console.log('Edit report:', report);
              // Would open edit modal here
            }}
          />
        </div>
      )}

      {/* Strategy View Tab */}
      {activeTab === 'strategy' && (
        <div className="space-y-6">
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* New Applicants by Month */}
            <Card>
              <h3 className="text-lg font-semibold text-gray-900 mb-4">
                New Applicants by Month
              </h3>
              {rollupsLoading ? (
                <div className="animate-pulse space-y-3">
                  {[...Array(6)].map((_, i) => (
                    <div key={i} className="h-4 bg-gray-200 rounded"></div>
                  ))}
                </div>
              ) : (
                <div className="space-y-3">
                  {rollups.map(rollup => (
                    <div key={rollup.month} className="flex justify-between items-center">
                      <span className="text-sm font-medium text-gray-600">
                        {rollup.month}
                      </span>
                      <span className="text-lg font-bold text-gray-900">
                        {rollup.new_applicants.toLocaleString()}
                      </span>
                    </div>
                  ))}
                  {rollups.length === 0 && (
                    <p className="text-gray-500 text-center py-4">No data available</p>
                  )}
                </div>
              )}
            </Card>

            {/* Linked Accounts Trend */}
            <Card>
              <h3 className="text-lg font-semibold text-gray-900 mb-4">
                Linked Accounts Trend
              </h3>
              {rollupsLoading ? (
                <div className="animate-pulse space-y-3">
                  {[...Array(6)].map((_, i) => (
                    <div key={i} className="h-4 bg-gray-200 rounded"></div>
                  ))}
                </div>
              ) : (
                <div className="space-y-3">
                  {rollups.map(rollup => (
                    <div key={rollup.month} className="flex justify-between items-center">
                      <span className="text-sm font-medium text-gray-600">
                        {rollup.month}
                      </span>
                      <span className="text-lg font-bold text-gray-900">
                        {rollup.linked_accounts.toLocaleString()}
                      </span>
                    </div>
                  ))}
                  {rollups.length === 0 && (
                    <p className="text-gray-500 text-center py-4">No data available</p>
                  )}
                </div>
              )}
            </Card>
          </div>

          {/* Summary Stats */}
          <Card>
            <h3 className="text-lg font-semibold text-gray-900 mb-4">Summary Statistics</h3>
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
              <div className="text-center">
                <div className="text-2xl font-bold text-gray-900">
                  {rollups.reduce((sum, r) => sum + r.new_applicants, 0).toLocaleString()}
                </div>
                <div className="text-sm text-gray-600">Total New Applicants</div>
              </div>
              <div className="text-center">
                <div className="text-2xl font-bold text-gray-900">
                  {rollups.reduce((sum, r) => sum + r.linked_accounts, 0).toLocaleString()}
                </div>
                <div className="text-sm text-gray-600">Total Linked Accounts</div>
              </div>
              <div className="text-center">
                <div className="text-2xl font-bold text-gray-900">
                  {rollups.length}
                </div>
                <div className="text-sm text-gray-600">Months of Data</div>
              </div>
              <div className="text-center">
                <div className="text-2xl font-bold text-gray-900">
                  {rollups.length > 0 ? 
                    Math.round(rollups.reduce((sum, r) => sum + r.new_applicants, 0) / rollups.length).toLocaleString() : 
                    '0'
                  }
                </div>
                <div className="text-sm text-gray-600">Avg Applicants/Month</div>
              </div>
            </div>
          </Card>
        </div>
      )}
    </div>
  );
};

